const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');
const path = require('path');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

// In-memory stores (use a database in production)
const users = new Map(); // username -> { passwordHash, salt }
const sessions = new Map(); // sessionToken -> { username, createdAt, expiresAt }
const leaderboard = []; // [{ username, score, timestamp }]
const activePlayers = new Map(); // socket.id -> { username, sessionToken, score, gameState }

const SESSION_DURATION = 3600000; // 1 hour

// Middleware
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// Utility functions
function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(password, salt, 10000, 64, 'sha512').toString('hex');
}

function generateSessionToken() {
  return crypto.randomBytes(48).toString('hex');
}

function isValidSession(token) {
  const sessionData = sessions.get(token);
  if (!sessionData) return false;
  if (Date.now() > sessionData.expiresAt) {
    sessions.delete(token);
    return false;
  }
  return true;
}

function getSessionUser(token) {
  if (!isValidSession(token)) return null;
  return sessions.get(token).username;
}

function validateUsername(username) {
  if (!username || typeof username !== 'string') return false;
  if (username.length < 3 || username.length > 20) return false;
  return /^[a-zA-Z0-9_]+$/.test(username);
}

function validateScore(score) {
  if (typeof score !== 'number') return false;
  if (!Number.isFinite(score)) return false;
  if (score < 0 || score > 999999999) return false;
  if (!Number.isInteger(score)) return false;
  return true;
}

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  return input.replace(/[<>&"']/g, (char) => {
    const entities = { '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&#39;' };
    return entities[char];
  });
}

function getTopLeaderboard(limit = 50) {
  return leaderboard
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((entry, index) => ({
      rank: index + 1,
      username: entry.username,
      score: entry.score,
      timestamp: entry.timestamp
    }));
}

function cleanExpiredSessions() {
  const now = Date.now();
  for (const [token, data] of sessions.entries()) {
    if (now > data.expiresAt) {
      sessions.delete(token);
    }
  }
}

// Clean expired sessions every 15 minutes
setInterval(cleanExpiredSessions, 900000);

// REST API endpoints for registration and login
app.post('/api/register', (req, res) => {
  const { username, password } = req.body;

  if (!validateUsername(username)) {
    return res.status(400).json({ error: 'Invalid username. Must be 3-20 alphanumeric characters or underscores.' });
  }

  if (!password || typeof password !== 'string' || password.length < 6 || password.length > 128) {
    return res.status(400).json({ error: 'Password must be between 6 and 128 characters.' });
  }

  if (users.has(username.toLowerCase())) {
    return res.status(409).json({ error: 'Username already exists.' });
  }

  const salt = crypto.randomBytes(32).toString('hex');
  const passwordHash = hashPassword(password, salt);

  users.set(username.toLowerCase(), {
    username: username,
    passwordHash,
    salt,
    createdAt: Date.now()
  });

  console.log(`[REGISTER] User registered: ${username}`);
  res.status(201).json({ message: 'Registration successful.' });
});

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password required.' });
  }

  const user = users.get(username.toLowerCase());
  if (!user) {
    return res.status(401).json({ error: 'Invalid credentials.' });
  }

  const passwordHash = hashPassword(password, user.salt);
  if (passwordHash !== user.passwordHash) {
    return res.status(401).json({ error: 'Invalid credentials.' });
  }

  const sessionToken = generateSessionToken();
  sessions.set(sessionToken, {
    username: user.username,
    createdAt: Date.now(),
    expiresAt: Date.now() + SESSION_DURATION
  });

  console.log(`[LOGIN] User logged in: ${user.username}`);
  res.json({ message: 'Login successful.', sessionToken, username: user.username });
});

app.get('/api/leaderboard', (req, res) => {
  const limit = Math.min(parseInt(req.query.limit) || 50, 100);
  res.json({ leaderboard: getTopLeaderboard(limit) });
});

// Socket.io connection handling
io.use((socket, next) => {
  const token = socket.handshake.auth.sessionToken;
  if (!token) {
    return next(new Error('Authentication required. Please provide a session token.'));
  }

  const username = getSessionUser(token);
  if (!username) {
    return next(new Error('Invalid or expired session. Please log in again.'));
  }

  socket.username = username;
  socket.sessionToken = token;
  next();
});

